<template>
  <div class="tool-section" data-tool="tokenCompress">
    <!-- 工具头部 -->
    <div
      class="section-header"
      style="
        display: flex;
        justify-content: space-between;
        align-items: center;
        padding: 15px 20px;
        background: linear-gradient(135deg, #2a3a4a 0%, #3a4a5a 100%);
        border: 1px solid rgba(220, 53, 69, 0.3);
        border-radius: 12px;
        margin-bottom: 4px;
        cursor: pointer;
        transition: all 0.3s ease;
      "
      @click="expanded = !expanded"
    >
      <h4
        style="margin: 0; color: #fff; font-size: 15px; font-weight: 600; display: flex; align-items: center; gap: 10px"
      >
        <i class="fa-solid fa-compress" style="color: #dc3545; font-size: 18px"></i>
        Token 压缩
      </h4>
      <i
        :class="expanded ? 'fa-solid fa-chevron-up' : 'fa-solid fa-chevron-down'"
        style="color: #888; font-size: 14px"
      ></i>
    </div>

    <div v-show="expanded" class="section-content" style="padding: 20px">
      <div class="tool-description" style="margin-bottom: 15px">
        <p style="margin: 0 0 8px 0; color: #ccc; font-size: 12px">
          <i class="fa-solid fa-info-circle" style="margin-right: 6px; color: #dc3545"></i>
          精简角色卡/世界书内容，在保留核心信息的前提下减少 Token 消耗。
        </p>
      </div>

      <!-- 读取来源 -->
      <div class="form-group" style="margin: 15px 0">
        <label style="display: block; margin-bottom: 8px; color: #ccc; font-size: 13px; font-weight: 500">
          读取内容：
        </label>
        <div style="display: flex; gap: 8px; flex-wrap: wrap">
          <button
            v-for="field in charFields"
            :key="field.key"
            style="
              padding: 6px 12px;
              background: #2a2a2a;
              border: 1px solid #3a3a3a;
              border-radius: 4px;
              color: #17a2b8;
              font-size: 11px;
              cursor: pointer;
            "
            @click="loadFromChar(field.key)"
          >
            {{ field.icon }} {{ field.label }}
          </button>
          <select
            v-model="selectedWorldbook"
            style="
              padding: 6px 10px;
              background: #2a2a2a;
              border: 1px solid #3a3a3a;
              border-radius: 4px;
              color: #10b981;
              font-size: 11px;
            "
            @change="loadFromWorldbook"
          >
            <option value="">📚 从世界书读取...</option>
            <option v-for="wb in availableWorldbooks" :key="wb" :value="wb">{{ wb }}</option>
          </select>
        </div>
      </div>

      <!-- 输入区域 -->
      <div class="form-group" style="margin: 15px 0">
        <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 8px">
          <label style="color: #ccc; font-size: 13px; font-weight: 500">原始内容：</label>
          <span style="color: #dc3545; font-size: 12px; font-weight: 600"> 约 {{ inputTokens }} tokens </span>
        </div>
        <textarea
          v-model="input"
          placeholder="粘贴或读取需要压缩的内容..."
          style="
            width: 100%;
            height: 120px;
            padding: 12px;
            background: #2a2a2a;
            border: 1px solid #3a3a3a;
            border-radius: 6px;
            color: #e0e0e0;
            font-size: 13px;
            resize: vertical;
            font-family: inherit;
          "
        ></textarea>
      </div>

      <!-- 压缩强度 -->
      <div class="form-group" style="margin: 15px 0">
        <label style="display: block; margin-bottom: 8px; color: #ccc; font-size: 13px; font-weight: 500">
          压缩强度：
        </label>
        <div style="display: flex; gap: 10px; flex-wrap: wrap">
          <label
            v-for="lvl in levels"
            :key="lvl.value"
            style="
              display: flex;
              align-items: center;
              gap: 6px;
              padding: 8px 14px;
              background: #2a2a2a;
              border-radius: 8px;
              cursor: pointer;
            "
            :style="{
              background: level === lvl.value ? lvl.color + '20' : '#2a2a2a',
              border: level === lvl.value ? '1px solid ' + lvl.color : '1px solid #3a3a3a',
            }"
          >
            <input v-model="level" type="radio" :value="lvl.value" style="display: none" />
            <span style="color: #e0e0e0; font-size: 12px">{{ lvl.label }}</span>
          </label>
        </div>
      </div>

      <!-- 进度条 -->
      <div v-if="isProcessing && progress > 0" style="margin: 15px 0">
        <div style="width: 100%; height: 8px; background: #2a2a2a; border-radius: 4px; overflow: hidden">
          <div
            :style="{
              width: progress + '%',
              height: '100%',
              background: '#dc3545',
              transition: 'width 0.3s',
            }"
          ></div>
        </div>
        <p style="margin: 5px 0 0 0; color: #dc3545; font-size: 11px; text-align: center">
          压缩中... {{ progress.toFixed(0) }}%
        </p>
      </div>

      <!-- 按钮 -->
      <div class="button-group" style="display: flex; gap: 12px; margin-bottom: 15px">
        <button
          :disabled="isProcessing || !input.trim()"
          style="
            padding: 10px 20px;
            background: rgba(30, 41, 59, 0.5);
            border: 1px solid #4a4a4a;
            border-radius: 6px;
            color: #e0e0e0;
            font-size: 13px;
            font-weight: 500;
            cursor: pointer;
          "
          @click="handleCompress"
        >
          <i class="fa-solid fa-compress" style="margin-right: 6px"></i>
          {{ isProcessing ? '压缩中...' : '压缩' }}
        </button>
        <button
          style="
            padding: 10px 20px;
            background: rgba(30, 41, 59, 0.5);
            border: 1px solid #4a4a4a;
            border-radius: 6px;
            color: #e0e0e0;
            font-size: 13px;
            cursor: pointer;
          "
          @click="clearForm"
        >
          <i class="fa-solid fa-trash" style="margin-right: 6px"></i>
          清空
        </button>
      </div>

      <!-- 输出区域 -->
      <div v-if="output" class="output-section">
        <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 12px">
          <h5 style="margin: 0; color: #fff; font-size: 14px; font-weight: 600">
            <i class="fa-solid fa-check-circle" style="margin-right: 6px; color: #28a745"></i>
            压缩结果：
          </h5>
          <div style="display: flex; gap: 12px; align-items: center">
            <span style="color: #28a745; font-size: 12px; font-weight: 600"> 约 {{ outputTokens }} tokens </span>
            <span
              style="
                padding: 4px 8px;
                background: rgba(40, 167, 69, 0.2);
                border-radius: 4px;
                color: #28a745;
                font-size: 11px;
                font-weight: 600;
              "
            >
              节省 {{ savedPercent }}%
            </span>
          </div>
        </div>
        <div
          style="
            background: #1e1e1e;
            border: 1px solid #3a3a3a;
            border-radius: 6px;
            padding: 15px;
            color: #e0e0e0;
            font-size: 13px;
            line-height: 1.6;
            white-space: pre-wrap;
            max-height: 200px;
            overflow-y: auto;
          "
        >
          {{ output }}
        </div>

        <div style="margin-top: 12px">
          <button
            style="
              padding: 8px 16px;
              background: rgba(30, 41, 59, 0.5);
              border: 1px solid #4a4a4a;
              border-radius: 6px;
              color: #e0e0e0;
              font-size: 12px;
              cursor: pointer;
            "
            @click="copyResult"
          >
            <i class="fa-solid fa-copy" style="margin-right: 6px"></i>
            复制
          </button>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { storeToRefs } from 'pinia';
import { computed, ref, watch } from 'vue';
import { useSettingsStore } from '../../settings';
import { copyToClipboard } from '../../utils';
import { callAIWithTavernSupport } from '../../utils/api';
import { translateError } from '../../utils/error-handler';

const settingsStore = useSettingsStore();
const { settings } = storeToRefs(settingsStore);

// Props
const props = defineProps<{
  availableWorldbooks: string[];
}>();

// Emits
const emit = defineEmits<{
  (e: 'dataChange', data: any): void;
}>();

// 状态
const expanded = ref(true);
const input = ref('');
const output = ref('');
const isProcessing = ref(false);
const progress = ref(0);
const level = ref<'light' | 'moderate' | 'aggressive'>('moderate');
const selectedWorldbook = ref('');

// 角色卡字段
const charFields = [
  { key: 'description', icon: '📝', label: '角色描述' },
  { key: 'personality', icon: '💭', label: '角色性格' },
  { key: 'scenario', icon: '🎬', label: '场景' },
];

// 压缩强度选项
const levels = [
  { value: 'light', label: '轻度 (保留细节)', color: '#10b981' },
  { value: 'moderate', label: '适度 (平衡)', color: '#ffc107' },
  { value: 'aggressive', label: '激进 (极简)', color: '#dc3545' },
] as const;

// Token 估算
const estimateTokens = (text: string): number => {
  if (!text) return 0;
  const chineseChars = (text.match(/[\u4e00-\u9fff]/g) || []).length;
  const englishWords = (text.match(/[a-zA-Z]+/g) || []).length;
  const numbers = (text.match(/\d+/g) || []).length;
  const punctuation = (text.match(/[^\w\s\u4e00-\u9fff]/g) || []).length;
  return Math.ceil(chineseChars * 2 + englishWords * 0.75 + numbers * 0.5 + punctuation * 0.5);
};

const inputTokens = computed(() => estimateTokens(input.value));
const outputTokens = computed(() => estimateTokens(output.value));
const savedPercent = computed(() => {
  if (!inputTokens.value || !outputTokens.value) return 0;
  const saved = ((inputTokens.value - outputTokens.value) / inputTokens.value) * 100;
  return Math.max(0, saved).toFixed(0);
});

// 监听数据变化
watch(
  [input, output, level],
  () => {
    emit('dataChange', {
      input: input.value,
      output: output.value,
      level: level.value,
    });
  },
  { deep: true },
);

// 从角色卡读取
const loadFromChar = (field: string) => {
  try {
    const tav = (window as any).TavernHelper;
    if (tav?.getCharData) {
      const char = tav.getCharData('current');
      if (char) {
        const fieldMap: Record<string, string> = {
          description: char.description || char.data?.description || '',
          personality: char.personality || char.data?.personality || '',
          scenario: char.scenario || char.data?.scenario || '',
        };
        const content = fieldMap[field] || '';
        if (content) {
          input.value = content;
          window.toastr.success(`已读取角色卡 ${field}`);
        } else {
          window.toastr.warning(`角色卡 ${field} 为空`);
        }
        return;
      }
    }
    window.toastr.warning('请先选择一个角色');
  } catch (e) {
    console.error('读取角色卡失败:', e);
    window.toastr.error('读取失败');
  }
};

// 从世界书读取
const loadFromWorldbook = async () => {
  if (!selectedWorldbook.value) return;

  try {
    const tav = (window as any).TavernHelper;
    if (tav?.getWorldbook) {
      const entries = await tav.getWorldbook(selectedWorldbook.value);
      if (entries?.length) {
        const allContent = entries
          .filter((e: any) => e.content)
          .map((e: any) => `【${e.name || e.comment || '条目'}】\n${e.content}`)
          .join('\n\n');
        if (allContent) {
          input.value = allContent;
          window.toastr.success(`已读取 ${entries.length} 个条目`);
        }
      }
    }
  } catch (e) {
    console.error('读取世界书失败:', e);
    window.toastr.error('读取失败');
  }
  selectedWorldbook.value = '';
};

// 处理压缩
const handleCompress = async () => {
  if (!input.value.trim()) {
    window.toastr.warning('请输入需要压缩的内容');
    return;
  }

  try {
    isProcessing.value = true;
    progress.value = 0;
    window.toastr.info('正在压缩...');

    const levelPrompts: Record<string, string> = {
      light: '轻度精简：删除明显冗余，保留所有细节，只减少约 10-20% 的长度',
      moderate: '适度精简：保留核心信息，精简冗长描述，减少约 30-40% 的长度',
      aggressive: '激进精简：只保留最核心信息，删除所有非必要描写，尽可能减少长度',
    };

    const systemPrompt = `你是一个专业的文本压缩专家。请按照以下要求压缩文本：

${levelPrompts[level.value]}

要求：
1. 保持原文的核心信息和逻辑
2. 保持原文的格式结构
3. 不要改变原文的语气和风格
4. 直接输出压缩后的内容，不要解释`;

    const messages = [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: `请压缩以下内容：\n\n${input.value}` },
    ];

    const result = await callAIWithTavernSupport(messages, settings.value, {
      onProgress: (p: number) => (progress.value = p),
    });

    output.value = result;
    window.toastr.success('压缩完成！');
  } catch (error) {
    console.error('Token 压缩失败:', error);
    window.toastr.error(translateError(error, '压缩'));
  } finally {
    isProcessing.value = false;
    progress.value = 0;
  }
};

// 复制结果
const copyResult = () => {
  if (!output.value) return;
  copyToClipboard(output.value, '压缩结果已复制');
};

// 清空表单
const clearForm = () => {
  input.value = '';
  output.value = '';
};

// 暴露方法
defineExpose({
  setExpanded: (val: boolean) => (expanded.value = val),
  loadData: (data: any) => {
    if (data) {
      input.value = data.input || '';
      output.value = data.output || '';
      level.value = data.level || 'moderate';
    }
  },
});
</script>
